import{_ as n,o as a,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"40. Absence On Defence Leave","description":"","frontmatter":{"title":"40. Absence On Defence Leave","eba":"Mental Health Services 2024-2028","topics":["leave"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/40-absence-on-defence-leave.md","filePath":"ebas/mental-health/common-terms/leave/40-absence-on-defence-leave.md"}'),r={name:"ebas/mental-health/common-terms/leave/40-absence-on-defence-leave.md"};function s(c,e,i,l,d,h){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_40-absence-on-defence-leave" tabindex="-1">40. Absence On Defence Leave <a class="header-anchor" href="#_40-absence-on-defence-leave" aria-label="Permalink to &quot;40. Absence On Defence Leave&quot;">​</a></h1><p><strong>40.1</strong> A Full Time or Part Time Employee absent on defence service will be reimbursed by the Employer an amount equal to the difference between:</p><p><strong>(a)</strong> the amount paid in respect of a period during which the Employee was absent on defence service; and</p><p><strong>(b)</strong> the amount the Employee could reasonably expect to have received from the Employer as earnings for that period had the Employee not been absent on defence service.</p><p><strong>40.2</strong> An Employee will notify the Employer as soon as possible of the date they require absence on defence service. The Employee will give the Employer proof that the absence relates to defence service, the duration of such absence and the amount received for the relevant defence service period.</p><p><strong>40.3</strong> In this clause &#39;absence on defence service&#39; has the meaning contained in section 24A of the Defence Reserve Service (Protection) Act 2001(Cth). Example: The Employee is on Defence Service leave in for the duration of a particular pay period. Were the employee not on Defence Service leave in that pay period they would have worked on Sunday and Monday of each week of the pay period. The Employee is entitled to payment as though at work for each of the Sundays and Mondays, less the amount of payment (not including reimbursements and the like) from the Defence Service for the Sundays and Mondays.</p><p>Plain language terms: ADF leave, reservist leave, military leave, defence force.</p>',7)])])}const f=n(r,[["render",s]]);export{m as __pageData,f as default};
